import React, { useState, useEffect } from 'react';
import { View, Text, Button, StyleSheet, Alert, ActivityIndicator } from 'react-native';
import * as AuthSession from 'expo-auth-session';
import * as WebBrowser from 'expo-web-browser';
import * as SecureStore from 'expo-secure-store';
import { makeRedirectUri } from 'expo-auth-session';

WebBrowser.maybeCompleteAuthSession();

const OAUTH_CONFIG = {
  authorizationEndpoint: 'https://oauth-provider.com/oauth/authorize',
  tokenEndpoint: 'https://oauth-provider.com/oauth/token',
  revocationEndpoint: 'https://oauth-provider.com/oauth/revoke',
  clientId: 'your-mobile-client-id',
  redirectUri: makeRedirectUri({
    scheme: 'yourapp',
    path: 'redirect'
  }),
  scopes: ['read', 'write', 'profile'],
  usePKCE: true,
};

const TOKEN_STORAGE_KEY = 'oauth_tokens';
const TOKEN_REFRESH_THRESHOLD = 300;

const App = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [userInfo, setUserInfo] = useState(null);
  const [isLoading, setIsLoading] = useState(true);

  const discovery = {
    authorizationEndpoint: OAUTH_CONFIG.authorizationEndpoint,
    tokenEndpoint: OAUTH_CONFIG.tokenEndpoint,
    revocationEndpoint: OAUTH_CONFIG.revocationEndpoint,
  };

  const [request, response, promptAsync] = AuthSession.useAuthRequest(
    {
      clientId: OAUTH_CONFIG.clientId,
      scopes: OAUTH_CONFIG.scopes,
      redirectUri: OAUTH_CONFIG.redirectUri,
      usePKCE: OAUTH_CONFIG.usePKCE,
      responseType: AuthSession.ResponseType.Code,
    },
    discovery
  );

  useEffect(() => {
    checkExistingAuth();
  }, []);

  useEffect(() => {
    if (response?.type === 'success') {
      const { code } = response.params;
      exchangeCodeForToken(code, request.codeVerifier);
    }
  }, [response]);

  const checkExistingAuth = async () => {
    try {
      const storedTokens = await SecureStore.getItemAsync(TOKEN_STORAGE_KEY);
      if (storedTokens) {
        const tokens = JSON.parse(storedTokens);
        if (await isTokenValid(tokens)) {
          setIsAuthenticated(true);
          await fetchUserInfo(tokens.access_token);
        } else {
          await refreshAccessToken(tokens.refresh_token);
        }
      }
    } catch (error) {
      console.error('Error checking existing auth:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const exchangeCodeForToken = async (code, codeVerifier) => {
    try {
      setIsLoading(true);
      
      const tokenRequestParams = {
        grant_type: 'authorization_code',
        code: code,
        redirect_uri: OAUTH_CONFIG.redirectUri,
        client_id: OAUTH_CONFIG.clientId,
        code_verifier: codeVerifier,
      };

      const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: Object.keys(tokenRequestParams)
          .map(key => `${encodeURIComponent(key)}=${encodeURIComponent(tokenRequestParams[key])}`)
          .join('&'),
      });

      const tokens = await response.json();

      if (response.ok) {
        await storeTokens(tokens);
        setIsAuthenticated(true);
        await fetchUserInfo(tokens.access_token);
      } else {
        Alert.alert('Authentication Error', tokens.error_description || 'Failed to obtain tokens');
      }
    } catch (error) {
      console.error('Token exchange error:', error);
      Alert.alert('Error', 'Failed to complete authentication');
    } finally {
      setIsLoading(false);
    }
  };

  const refreshAccessToken = async (refreshToken) => {
    try {
      setIsLoading(true);

      const tokenRequestParams = {
        grant_type: 'refresh_token',
        refresh_token: refreshToken,
        client_id: OAUTH_CONFIG.clientId,
      };

      const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: Object.keys(tokenRequestParams)
          .map(key => `${encodeURIComponent(key)}=${encodeURIComponent(tokenRequestParams[key])}`)
          .join('&'),
      });

      const tokens = await response.json();

      if (response.ok) {
        await storeTokens(tokens);
        setIsAuthenticated(true);
        await fetchUserInfo(tokens.access_token);
        return true;
      } else {
        await SecureStore.deleteItemAsync(TOKEN_STORAGE_KEY);
        setIsAuthenticated(false);
        return false;
      }
    } catch (error) {
      console.error('Token refresh error:', error);
      await SecureStore.deleteItemAsync(TOKEN_STORAGE_KEY);
      setIsAuthenticated(false);
      return false;
    } finally {
      setIsLoading(false);
    }
  };

  const storeTokens = async (tokens) => {
    const tokenData = {
      access_token: tokens.access_token,
      refresh_token: tokens.refresh_token,
      expires_in: tokens.expires_in,
      token_type: tokens.token_type,
      timestamp: Date.now(),
    };
    await SecureStore.setItemAsync(TOKEN_STORAGE_KEY, JSON.stringify(tokenData));
  };

  const isTokenValid = async (tokens) => {
    const expirationTime = tokens.timestamp + (tokens.expires_in * 1000) - (TOKEN_REFRESH_THRESHOLD * 1000);
    return Date.now() < expirationTime;
  };

  const fetchUserInfo = async (accessToken) => {
    try {
      const response = await fetch('https://oauth-provider.com/api/userinfo', {
        headers: {
          Authorization: `Bearer ${accessToken}`,
        },
      });

      if (response.ok) {
        const userData = await response.json();
        setUserInfo(userData);
      }
    } catch (error) {
      console.error('Error fetching user info:', error);
    }
  };

  const makeAuthenticatedRequest = async (url, options = {}) => {
    try {
      const storedTokens = await SecureStore.getItemAsync(TOKEN_STORAGE_KEY);
      if (!storedTokens) {
        throw new Error('No tokens available');
      }

      let tokens = JSON.parse(storedTokens);

      if (!(await isTokenValid(tokens))) {
        const refreshed = await refreshAccessToken(tokens.refresh_token);
        if (!refreshed) {
          throw new Error('Failed to refresh token');
        }
        const newTokens = await SecureStore.getItemAsync(TOKEN_STORAGE_KEY);
        tokens = JSON.parse(newTokens);
      }

      const response = await fetch(url, {
        ...options,
        headers: {
          ...options.headers,
          Authorization: `Bearer ${tokens.access_token}`,
        },
      });

      return response;
    } catch (error) {
      console.error('Authenticated request error:', error);
      throw error;
    }
  };

  const handleLogin = async () => {
    try {
      await promptAsync({ useProxy: false });
    } catch (error) {
      console.error('Login error:', error);
      Alert.alert('Error', 'Failed to initiate login');
    }
  };

  const handleLogout = async () => {
    try {
      const storedTokens = await SecureStore.getItemAsync(TOKEN_STORAGE_KEY);
      if (storedTokens) {
        const tokens = JSON.parse(storedTokens);
        
        await fetch(OAUTH_CONFIG.revocationEndpoint, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/x-www-form-urlencoded',
          },
          body: `token=${tokens.access_token}&client_id=${OAUTH_CONFIG.clientId}`,
        });
      }

      await SecureStore.deleteItemAsync(TOKEN_STORAGE_KEY);
      setIsAuthenticated(false);
      setUserInfo(null);
    } catch (error) {
      console.error('Logout error:', error);
      Alert.alert('Error', 'Failed to logout');
    }
  };

  const testApiCall = async () => {
    try {
      const response = await makeAuthenticatedRequest('https://oauth-provider.com/api/protected-resource');
      const data = await response.json();
      Alert.alert('API Response', JSON.stringify(data, null, 2));
    } catch (error) {
      Alert.alert('Error', 'Failed to make API call');
    }
  };

  if (isLoading) {
    return (
      <View style={styles.container}>
        <ActivityIndicator size="large" color="#0000ff" />
      </View>
    );
  }

  return (
    <View style={styles.container}>
      <Text style={styles.title}>OAuth 2.0 Authentication</Text>
      
      {!isAuthenticated ? (
        <View style={styles.buttonContainer}>
          <Button title="Login with OAuth" onPress={handleLogin} disabled={!request} />
        </View>
      ) : (
        <View style={styles.authenticatedContainer}>
          <Text style={styles.welcomeText}>Welcome!</Text>
          {userInfo && (
            <View style={styles.userInfoContainer}>
              <Text style={styles.userInfoText}>User ID: {userInfo.id || 'N/A'}</Text>
              <Text style={styles.userInfoText}>Email: {userInfo.email || 'N/A'}</Text>
              <Text style={styles.userInfoText}>Name: {userInfo.name || 'N/A'}</Text>
            </View>
          )}
          <View style={styles.buttonContainer}>
            <Button title="Test API Call" onPress={testApiCall} />
            <View style={styles.buttonSpacer} />
            <Button title="Logout" onPress={handleLogout} color="#ff0000" />
          </View>
        </View>
      )}
    </View>
  );
};

